// Extract shipment data from request body
const shipment = $input.item.json.body || $input.item.json;

// Define required fields
const required = ['origin', 'destination', 'weight', 'length', 'width', 'height'];

// Check for missing fields
const missing = required.filter(field => !shipment[field]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate numeric values
const numericFields = ['weight', 'length', 'width', 'height'];
for (const field of numericFields) {
  const value = parseFloat(shipment[field]);
  if (isNaN(value) || value <= 0) {
    throw new Error(`Invalid ${field}: must be a positive number`);
  }
}

// Structure the data
const structured = {
  origin: {
    postalCode: shipment.origin.postalCode || shipment.origin,
    country: shipment.origin.country || 'IN'
  },
  destination: {
    postalCode: shipment.destination.postalCode || shipment.destination,
    country: shipment.destination.country || 'IN'
  },
  package: {
    weight: parseFloat(shipment.weight),
    length: parseFloat(shipment.length),
    width: parseFloat(shipment.width),
    height: parseFloat(shipment.height)
  },
  preferences: {
    deliverySpeed: shipment.deliverySpeed || 'standard',
    insurance: Boolean(shipment.insurance),
    cod: Boolean(shipment.cod),
    autoBook: Boolean(shipment.autoBook)
  },
  metadata: {
    requestId: `REQ-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    requestedAt: new Date().toISOString()
  }
};

// Calculate volumetric weight (standard divisor: 5000 for cm³ to kg)
structured.package.volumetricWeight = 
  (structured.package.length * structured.package.width * structured.package.height) / 5000;

// Calculate chargeable weight (higher of actual or volumetric)
structured.package.chargeableWeight = Math.max(
  structured.package.weight,
  structured.package.volumetricWeight
);

return { json: structured };

// Get shipment details and carrier responses
const shipment = $('Validate input and calculate weights').item.json;
const fedex = $('Get FedEx rates').item.json;
const dhl = $('Get DHL rates').item.json;
const bluedart = $('Get BlueDart rates').item.json;
const delhivery = $('Get Delhivery rates').item.json;

const rates = [];

// Parse FedEx response
try {
  if (fedex && !fedex.error && fedex.output?.rateReplyDetails) {
    const fedexRate = fedex.output.rateReplyDetails[0];
    rates.push({
      carrier: 'FedEx',
      cost: parseFloat(fedexRate.ratedShipmentDetails?.[0]?.totalNetCharge || 0),
      currency: fedexRate.ratedShipmentDetails?.[0]?.currency || 'INR',
      transitDays: parseInt(fedexRate.commit?.transitTime || 999),
      service: fedexRate.serviceName || 'Standard',
      available: true
    });
  }
} catch (error) {
  console.log('FedEx parsing error:', error.message);
}

// Parse DHL response
try {
  if (dhl && !dhl.error && dhl.products && dhl.products.length > 0) {
    const dhlRate = dhl.products[0];
    rates.push({
      carrier: 'DHL',
      cost: parseFloat(dhlRate.totalPrice?.[0]?.price || 0),
      currency: dhlRate.totalPrice?.[0]?.priceCurrency || 'INR',
      transitDays: parseInt(dhlRate.deliveryCapabilities?.estimatedDeliveryDateAndTime ? 
        Math.ceil((new Date(dhlRate.deliveryCapabilities.estimatedDeliveryDateAndTime) - new Date()) / (1000 * 60 * 60 * 24)) : 999),
      service: dhlRate.productName || 'Standard',
      available: true
    });
  }
} catch (error) {
  console.log('DHL parsing error:', error.message);
}

// Parse BlueDart response
try {
  if (bluedart && !bluedart.error && bluedart.Response) {
    rates.push({
      carrier: 'BlueDart',
      cost: parseFloat(bluedart.Response.Charges?.TotalAmount || 0),
      currency: 'INR',
      transitDays: parseInt(bluedart.Response.TransitDays || 999),
      service: bluedart.Response.ServiceType || 'Standard',
      available: bluedart.Response.Status === 'Success'
    });
  }
} catch (error) {
  console.log('BlueDart parsing error:', error.message);
}

// Parse Delhivery response
try {
  if (delhivery && !delhivery.error && Array.isArray(delhivery) && delhivery.length > 0) {
    const delhiveryRate = delhivery[0];
    rates.push({
      carrier: 'Delhivery',
      cost: parseFloat(delhiveryRate.total_amount || 0),
      currency: 'INR',
      transitDays: parseInt(delhiveryRate.transit_time || 999),
      service: delhiveryRate.mode || 'Standard',
      available: true
    });
  }
} catch (error) {
  console.log('Delhivery parsing error:', error.message);
}

// Filter out invalid rates and sort by cost
const validRates = rates.filter(r => r.cost > 0 && r.available);

if (validRates.length === 0) {
  throw new Error('No valid rates received from any carrier. Please check API credentials and service availability.');
}

// Sort rates by cost (lowest first)
validRates.sort((a, b) => a.cost - b.cost);

return {
  json: {
    shipmentDetails: shipment,
    rates: validRates,
    ratesCount: validRates.length,
    carriersQueried: 4,
    carriersResponded: validRates.length
  }
};

