// Extract AI response
const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Clean JSON from markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let aiRecommendation;
try {
  aiRecommendation = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse AI response: ${error.message}. Response was: ${cleanText}`);
}

// Get normalized rates data
const ratesData = $('Parse and normalize carrier rates').item.json;

// Find the recommended carrier in rates
const recommended = ratesData.rates.find(
  r => r.carrier.toLowerCase() === aiRecommendation.recommendedCarrier.toLowerCase()
);

if (!recommended) {
  throw new Error(`Recommended carrier "${aiRecommendation.recommendedCarrier}" not found in available rates`);
}

// Calculate comparison metrics
const sorted = [...ratesData.rates].sort((a, b) => a.cost - b.cost);
const cheapest = sorted[0];
const fastest = [...ratesData.rates].sort((a, b) => a.transitDays - b.transitDays)[0];
const mostExpensive = sorted[sorted.length - 1];

const savingsVsMostExpensive = mostExpensive.cost - recommended.cost;
const extraCostVsCheapest = recommended.cost - cheapest.cost;

return {
  json: {
    requestId: ratesData.shipmentDetails.metadata.requestId,
    recommended: {
      ...recommended,
      reasoning: aiRecommendation.reasoning,
      valueScore: aiRecommendation.valueScore
    },
    comparison: {
      cheapestCarrier: cheapest.carrier,
      cheapestCost: cheapest.cost.toFixed(2),
      fastestCarrier: fastest.carrier,
      fastestTransitDays: fastest.transitDays,
      savingsVsMostExpensive: savingsVsMostExpensive.toFixed(2),
      extraCostVsCheapest: extraCostVsCheapest.toFixed(2),
      totalOptionsCompared: ratesData.rates.length
    },
    allRates: sorted,
    shipmentDetails: ratesData.shipmentDetails
  }
};

const response = $input.item.json;
const carrier = response.recommended.carrier;

// Map carriers to their booking endpoints
const carrierEndpoints = {
  'FedEx': 'https://api.fedex.com/ship/v1/shipments',
  'DHL': 'https://api-eu.dhl.com/mydhlapi/v1/shipments',
  'BlueDart': 'https://api.bluedart.com/servlet/RoutingServlet',
  'Delhivery': 'https://track.delhivery.com/api/cmu/create.json'
};

const endpoint = carrierEndpoints[carrier];

if (!endpoint) {
  throw new Error(`No booking endpoint configured for carrier: ${carrier}`);
}

// Generate unique booking reference
const bookingRef = `BK-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

return {
  json: {
    carrier,
    endpoint,
    shipmentData: response.shipmentDetails,
    recommendedService: response.recommended.service,
    estimatedCost: response.recommended.cost,
    bookingRef
  }
};

const bookingResponse = $input.item.json;
const preparedData = $('Prepare booking request').item.json;
const recommendation = $('Build final response').item.json;

// Extract tracking number from various carrier response formats
let trackingNumber = 'PENDING';

if (bookingResponse.tracking_number) {
  trackingNumber = bookingResponse.tracking_number;
} else if (bookingResponse.trackingNumber) {
  trackingNumber = bookingResponse.trackingNumber;
} else if (bookingResponse.trackingId) {
  trackingNumber = bookingResponse.trackingId;
} else if (bookingResponse.shipmentIdentificationNumber) {
  trackingNumber = bookingResponse.shipmentIdentificationNumber;
}

return {
  json: {
    success: true,
    booked: true,
    status: 'Shipment booked successfully',
    carrier: recommendation.recommended.carrier,
    trackingNumber,
    estimatedCost: recommendation.recommended.cost,
    currency: recommendation.recommended.currency,
    estimatedTransitDays: recommendation.recommended.transitDays,
    service: recommendation.recommended.service,
    savings: recommendation.comparison.savingsVsMostExpensive,
    bookingRef: preparedData.bookingRef,
    requestId: recommendation.requestId
  }
};

const response = $input.item.json;

return {
  json: {
    success: true,
    booked: false,
    status: 'Quote generated - manual booking required',
    message: 'Rate comparison completed. Enable autoBook in request to book automatically.',
    recommended: {
      carrier: response.recommended.carrier,
      cost: response.recommended.cost,
      currency: response.recommended.currency,
      transitDays: response.recommended.transitDays,
      service: response.recommended.service,
      reasoning: response.recommended.reasoning,
      valueScore: response.recommended.valueScore
    },
    comparison: response.comparison,
    allRates: response.allRates.map(rate => ({
      carrier: rate.carrier,
      cost: rate.cost,
      currency: rate.currency,
      transitDays: rate.transitDays,
      service: rate.service
    })),
    requestId: response.requestId
  }
};
